import { crateApi } from '@reduxjs/toolkit/query';

export const todoApi = crateApi({
    reducerPath: 'todoApi',
    baseQuery: fetchBaseQuery({ baseUrl: 'https://jsonplaceholder.typicode.com/' }),
    endPoints: (builder) => ({
        getTodos: builder.query({
            query: () => 'todos'
        })
    })
});

export const { useGetTodosQuery } = todoApi;
